document.addEventListener("DOMContentLoaded",function(){const navLinks=document.querySelectorAll(".navbar-nav .nav-link");const sections=document.querySelectorAll("section");document.querySelector('.nav-link[href="#"]').classList.add("active");window.addEventListener("scroll",function(){let current="";sections.forEach((section)=>{const sectionTop=section.offsetTop;const sectionHeight=section.clientHeight;if(pageYOffset>=sectionTop-sectionHeight/3){current=section.getAttribute("id")}});navLinks.forEach((link)=>{link.classList.remove("active");if(link.getAttribute("href").includes(current)){link.classList.add("active")}});if(!current){document.querySelector('.nav-link[href="#"]').classList.add("active")}});navLinks.forEach((link)=>{link.addEventListener("click",function(){navLinks.forEach((link)=>link.classList.remove("active"));this.classList.add("active")})})});document.addEventListener("DOMContentLoaded",function(){const navLinks=document.querySelectorAll(".navbar-nav .nav-link");const navbarCollapse=document.querySelector(".navbar-collapse");navLinks.forEach((link)=>{link.addEventListener("click",function(){if(navbarCollapse.classList.contains("show")){navbarCollapse.classList.remove("show")}})})});document.addEventListener("DOMContentLoaded",function(){var swiperCube=new Swiper(".swiper-cube",{effect:"cube",grabCursor:!0,cubeEffect:{shadow:!1,slideShadows:!0,shadowOffset:20,shadowScale:0.94,},pagination:{el:".swiper-pagination"},autoplay:{delay:3000,disableOnInteraction:!1},})});document.addEventListener("DOMContentLoaded",function(){var backToTopButton=document.getElementById("backToTop");window.addEventListener("scroll",function(){if(window.scrollY>300){backToTopButton.style.display="block"}else{backToTopButton.style.display="none"}});backToTopButton.addEventListener("click",function(e){e.preventDefault();window.scrollTo({top:0,behavior:"smooth"})})});document.addEventListener("click",function(event){var navbar=document.getElementById("navbarSupportedContent");var isClickInside=navbar.contains(event.target);if(!isClickInside){var navbarToggler=document.querySelector(".navbar-toggler");var isExpanded=navbarToggler.getAttribute("aria-expanded")==="true";if(isExpanded){navbarToggler.click()}}});var typed=new Typed("#typed-text",{strings:["I'm Danil Aziz"],typeSpeed:130,backSpeed:50,showCursor:!0,cursorChar:"|",loop:!0,});function getDeviceInfoAndLocation(){var deviceInfo=navigator.userAgent;document.getElementById("device_info").value=deviceInfo;if(navigator.geolocation){navigator.geolocation.getCurrentPosition(function(position){var location="Latitude: "+position.coords.latitude+", Longitude: "+position.coords.longitude;document.getElementById("location").value=location})}else{document.getElementById("location").value="Geolocation is not supported by this browser."}}
const urlParams=new URLSearchParams(window.location.search);if(urlParams.has("success")){document.getElementById("contactForm").reset();window.history.replaceState({},document.title,window.location.pathname)}
document.addEventListener("DOMContentLoaded",function(){document.getElementById("contactForm").style.display="block"});document.addEventListener("DOMContentLoaded",function(){const form=document.getElementById("contactForm");const submitButton=form.querySelector("button[type='submit']");const inputs=form.querySelectorAll("input, textarea");function checkFormValidity(){let isValid=!0;inputs.forEach((input)=>{if(input.value.trim()===""){isValid=!1}});if(isValid){submitButton.classList.remove("inactive");submitButton.disabled=!1;submitButton.style.pointerEvents="auto";submitButton.style.backgroundColor="";submitButton.style.color=""}else{submitButton.classList.add("inactive");submitButton.disabled=!0;submitButton.style.pointerEvents="none";submitButton.style.backgroundColor="#ccc";submitButton.style.color="#888"}}
inputs.forEach((input)=>{input.addEventListener("input",checkFormValidity)});checkFormValidity();form.addEventListener("submit",function(e){e.preventDefault();var name=document.getElementById("name").value.trim();var email=document.getElementById("email").value.trim();var message=document.getElementById("message").value.trim();var phone="6287728890135";var text="Nama: "+name+"%0A"+"Email: "+email+"%0A"+"Pesan: "+message;var url="https://wa.me/"+phone+"?text="+text;window.open(url,"_blank");form.reset();checkFormValidity()})})